const raw_connect = require('amqplib/lib/connect').connect;
const ChannelModel = require('amqplib/lib/channel_model').ChannelModel;
const promisify = require('node:util').promisify;

function connect(url, connOptions) {
  return promisify((cb) => raw_connect(url, connOptions, cb))().then((conn) => new ChannelModel(conn));
}

module.exports.connect = connect;
module.exports.credentials = require('amqplib/lib/credentials');
module.exports.IllegalOperationError = require('amqplib/lib/error').IllegalOperationError;
